fn decode_ansi_line(line: &str) -> String {
    line.replace(r"\033", "\x1b")
}

pub fn acm_logo_lines() -> Vec<String> {
    CODEX_LOGO_RAW
        .iter()
        .map(|line| decode_ansi_line(line))
        .collect()
}

pub fn brand_logo_lines() -> Vec<String> {
    brand()
        .logo
        .lines
        .iter()
        .map(|line| decode_ansi_line(line))
        .collect()
}
